        {
          "source": "support tickets",
          "citation": "20% of PR comments link to tracker"
        }
      ]
    },
    {
      "title": "Time tracking",
      "moscow": "Should",
      "evidence": [
        {
          "source": "billing pain",
          "citation": "hours pulled from notes weekly"
        }
      ]
    },
    {
      "title": "Custom dashboards",
      "moscow": "Could",
      "evidence": [
        {
          "source": "stakeholder asks",
          "citation": "exec wants weekly snapshot"
        }
      ]
    },
    {
      "title": "On-prem deployment",
      "moscow": "Won't",
      "evidence": [
        {
          "source": "infra ADR-009",
